export function getQuestionsByChapter(chapterId: number): Question[] {
  return questions.filter(q => q.chapterId === chapterId);
}

export function getRandomQuestions(count: number, chapterId?: number, difficulty?: string): Question[] {
  let filtered = chapterId ? questions.filter(q => q.chapterId === chapterId) : [...questions];
  if (difficulty) {
    filtered = filtered.filter(q => q.difficulty === difficulty);
  }
  const shuffled = filtered.sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}

export function getQuestionsForMockTest(count: number = 24): Question[] {
  const shuffled = [...questions].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}

export function getQuestionsForQuickFire(count: number = 10): Question[] {
  const shuffled = [...questions].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}
